// Construit la soumission Docuseal a partir du MODELE reutilisable (free edition)
// en pre-remplissant les champs du devis (mise en page "vrai devis").
const body = $json.body || $json;

// ID du modele Docuseal
const TEMPLATE_ID = 1;

// Format monetaire francais : "5 000,00 €"
const eur = (v) => {
  const p = Number(v || 0).toFixed(2).split('.');
  const i = p[0].replace(/\B(?=(\d{3})+(?!\d))/g, ' ');
  return i + ',' + p[1] + ' €';
};

const ht = Number(body.devis_total_ht) || 0;
const ttc = Number(body.devis_total_ttc) || 0;
const tvaVal = Math.round((ttc - ht) * 100) / 100;
const dateEmission = DateTime.now().setZone('Europe/Paris').toFormat('dd/LL/yyyy');

const nomComplet = ((body.prenom || '') + ' ' + (body.nom || '')).trim();

// POUR (client)
const client = [
  body.societe || nomComplet,
  body.societe ? nomComplet : '',
  body.adresse || '',
  body.telephone ? 'Tel. : ' + body.telephone : '',
].filter(Boolean).join('\n');

// Lieu du chantier
const chantier = body.adresse || '';

// Designation des ouvrages (cellule du tableau)
const designation = [
  "Expertise et diagnostic d'etancheite — toiture " + (body.type_toiture || '') + ', ' + (body.surface_m2 || '') + ' m2',
  'Intervention le ' + (body.date_formatee || '') + ' (' + (body.heure || '') + ')   Acces : ' + (body.accessibilite || ''),
  body.etat_general ? 'Etat constate : ' + body.etat_general : '',
  'Honoraires : ' + eur(body.devis_honoraires) + '    Deplacement ' + (body.devis_distance_km || 0) + ' km : ' + eur(body.devis_deplacement),
  body.description || '',
].filter(Boolean).join('\n');

// Email de demande de signature personnalise (concis).
// {{submitter.link}} est remplace par Docuseal par le bouton/lien securise de signature.
const emailSubject = 'Votre devis à signer — Normandie Étanchéité';
const emailBody = [
  'Bonjour ' + (body.prenom || '') + ',',
  '',
  'Votre devis est prêt.',
  '',
  'Examiner et signer : {{submitter.link}}',
  '',
  'Merci,',
  'Normandie Étanchéité',
].join('\n');

// Metadonnees transportees jusqu'au webhook form.completed (RDV calendrier)
const metadata = {
  date: body.date || '',
  heure: body.heure || '',
  prenom: body.prenom || '',
  nom: body.nom || '',
  telephone: body.telephone || '',
  email: body.email || '',
  adresse: body.adresse || '',
  surface_m2: String(body.surface_m2 || ''),
  type_toiture: body.type_toiture || '',
  devis_total_ttc: String(body.devis_total_ttc || ''),
  devis_numero: body.devis_numero || '',
};

const submissionData = {
  template_id: TEMPLATE_ID,
  send_email: true,
  submitters: [
    {
      role: 'Client',
      name: nomComplet,
      email: body.email,
      values: {
        numero: body.devis_numero || '',
        date: dateEmission,
        client,
        chantier,
        designation,
        montant_ht: eur(ht),
        total_ht: eur(ht),
        tva: eur(tvaVal),
        total_ttc: eur(ttc),
      },
      message: {
        subject: emailSubject,
        body: emailBody,
      },
      metadata,
    },
  ],
};

return [{ json: { submissionData } }];
